1	// claim-office.ts
2	
3	const PROCESSING_FEE = 5;
4	const FIRST_INSURANCE_SURCHARGE = 0.1;
5	
6	const BASE_PREMIUMS: Record<string, number> = {
7	  sword: 100,
8	  amulet: 60,
9	  staff: 80,
10	  potion: 40,
11	  rune: 25,
12	  moonstone: 25,
13	};
14	
15	type Item = { type: string };
16	type Step = { op: string; items: Item[] };
17	type Scenario = { steps: Step[] };
18	
19	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
20	const BLOCK_SIZE = 3;
21	const BLOCK_BASE_PREMIUM = 60;
22	
23	const itemBasePremium = (item: Item): number => BASE_PREMIUMS[item.type] ?? 0;
24	
25	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
26	
27	const countByType = (items: Item[]): Map<string, number> => {
28	  const counts = new Map<string, number>();
29	  for (const item of items) {
30	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
31	  }
32	  return counts;
33	};
34	
35	const componentGroupPremium = (type: string, count: number): number =>
36	  count === BLOCK_SIZE ? BLOCK_BASE_PREMIUM : count * (BASE_PREMIUMS[type] ?? 0);
37	
38	const sumItemBasePremiums = (items: Item[]): number => {
39	  const nonComponents = items.filter((item) => !isComponent(item));
40	  const components = items.filter(isComponent);
41	  const nonComponentsTotal = nonComponents.reduce(
42	    (sum, item) => sum + itemBasePremium(item),
43	    0,
44	  );
45	  const componentsTotal = Array.from(countByType(components)).reduce(
46	    (sum, [type, count]) => sum + componentGroupPremium(type, count),
47	    0,
48	  );
49	  return nonComponentsTotal + componentsTotal;
50	};
51	
52	export function runScenario(scenario: unknown): { results: { premium: number }[] } {
53	  const step = (scenario as Scenario).steps[0];
54	  const itemsBase = sumItemBasePremiums(step.items);
55	  const policyBase = itemsBase + itemsBase * FIRST_INSURANCE_SURCHARGE;
56	  const premium = Math.ceil(policyBase + PROCESSING_FEE);
57	  return { results: [{ premium }] };
58	}
